// FN_SplitBaloes v2 (v2.0.1) — emite 1 item por balão, sem intermediário.
// Regra principal: se todo o texto cabe em MAX chars, 1 balão único (preserva \n internos).
// Quebras de linha simples dentro de 1 balão são INTENCIONAIS (listas, estrutura).
// Só fragmenta em múltiplos balões se o texto total > MAX chars.
const raw = ($input.first().json.raw_text || '').toString();
let txt = raw
  .replace(/```[\s\S]*?```/g, m => m.replace(/```/g,''))
  .replace(/`([^`]*)`/g, '$1')
  .replace(/\*\*([^*]+)\*\*/g, '$1')
  .replace(/__([^_]+)__/g, '$1')
  .replace(/\*([^*]+)\*/g, '$1')
  .replace(/_([^_]+)_/g, '$1')
  .replace(/^#{1,6}\s+/gm, '')
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
  .replace(/\r/g, '')
  .trim();

if (!txt) return [];

const MAX = 700;

// CASO FELIZ: texto inteiro cabe em 1 balão — preserva listas, numeração, tudo.
if (txt.length <= MAX) {
  return [{ json: { output: txt } }];
}

// CASO LONGO: quebra por parágrafos (\n\n+). Cada parágrafo vira 1 balão.
// Se parágrafo individual > MAX, quebra por sentença.
const paragraphs = txt.split(/\n{2,}/).map(p => p.trim()).filter(Boolean);
const baloes = [];
for (const p of paragraphs) {
  if (p.length <= MAX) {
    baloes.push(p);
    continue;
  }
  const sentences = p.split(/(?<=[.!?])\s+/);
  let buf = '';
  for (const s of sentences) {
    if ((buf + ' ' + s).trim().length > MAX && buf) {
      baloes.push(buf.trim());
      buf = s;
    } else {
      buf = buf ? buf + ' ' + s : s;
    }
  }
  if (buf.trim()) baloes.push(buf.trim());
}

// Emite 1 item por balão. Loop Enviar Mensagens itera diretamente.
return baloes.map(b => ({ json: { output: b } }));
